mapper.select:
SELECT id, seat_id, reader_id, reservation_id, checkin_time, checkout_time, status
FROM seat_checkin WHERE seat_id = #{seatId}
ORDER BY checkin_time DESC

SELECT id, seat_id, reader_id, reservation_id, checkin_time, checkout_time, status
FROM seat_checkin WHERE reader_id = #{readerId}
ORDER BY checkin_time DESC

mapper.update:
UPDATE seat_checkin
SET checkout_time = #{checkoutTime},
    status = #{status}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) FROM seat_checkin
WHERE DAYOFWEEK(checkin_time) = #{dayOfWeek}
AND HOUR(checkin_time) = #{hour}
AND status = 1

SELECT COUNT(*) FROM seat_checkin
WHERE seat_id = #{seatId}
AND checkin_time BETWEEN #{startDate} AND #{endDate}
